// Create the accounts table with a JSONB doc column.
// Export an async function ensureSchema(db) that runs CREATE TABLE IF NOT EXISTS.
// Design: account_id TEXT PRIMARY KEY + doc JSONB NOT NULL + a GIN index on doc.
import { withDb } from "./db.mjs";

export async function ensureSchema(db) {
  await db.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL
    )
  `);
  await db.query(`
    CREATE INDEX IF NOT EXISTS accounts_doc_gin_idx
    ON accounts
    USING GIN (doc)
  `);
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client))
    .then(() => console.log("schema ready"))
    .catch((e) => {
      console.error(e);
      process.exit(1);
    });
}

// Implement CRUD for the accounts resource against the live DB.
// Each function receives the pg client (with search_path set to the run schema) from src/db.mjs.
// Call ensureSchema(db) from src/schema.mjs before the first write.
import { ensureSchema } from "./schema.mjs";

const ALLOWED_TIERS = new Set(["strategic", "midmarket", "standard"]);
const ALLOWED_STATUSES = new Set(["active", "at-risk", "churned"]);

function stripUndefined(values) {
  const result = {};
  for (const [key, value] of Object.entries(values ?? {})) {
    if (value !== undefined) {
      result[key] = value;
    }
  }
  return result;
}

function normalizeCreatedAt(value) {
  if (value instanceof Date) {
    return value.toISOString();
  }
  return value;
}

function validateAccountDoc(doc) {
  if (typeof doc.accountId !== "string" || doc.accountId.length === 0) {
    throw new Error("accountId is required");
  }
  if (typeof doc.name !== "string" || doc.name.length === 0) {
    throw new Error("name is required");
  }
  if (!ALLOWED_TIERS.has(doc.tier)) {
    throw new Error("tier is invalid");
  }
  if (!ALLOWED_STATUSES.has(doc.status)) {
    throw new Error("status is invalid");
  }
  if (doc.createdAt === undefined || doc.createdAt === null) {
    throw new Error("createdAt is required");
  }
}

function hydrateRow(row) {
  if (!row) {
    return null;
  }
  return { ...row.doc, accountId: row.account_id };
}

// Create a accounts record. Return the created document.
export async function createAccounts(db, data) {
  await ensureSchema(db);

  const doc = {
    ...stripUndefined(data),
    accountId: data?.accountId,
    createdAt: normalizeCreatedAt(data?.createdAt ?? new Date()),
  };
  validateAccountDoc(doc);

  const result = await db.query(
    `
      INSERT INTO accounts (account_id, doc)
      VALUES ($1, $2::jsonb)
      ON CONFLICT (account_id) DO UPDATE
      SET doc = EXCLUDED.doc
      RETURNING account_id, doc
    `,
    [doc.accountId, doc],
  );
  return hydrateRow(result.rows[0]);
}

// Read a accounts by its id. Return the document or null.
export async function getAccounts(db, id) {
  const result = await db.query(
    `
      SELECT account_id, doc
      FROM accounts
      WHERE account_id = $1
    `,
    [id],
  );
  return hydrateRow(result.rows[0]);
}

// Update a accounts by id with partial data. Return the updated document.
export async function updateAccounts(db, id, data) {
  const existing = await db.query(
    `
      SELECT account_id, doc
      FROM accounts
      WHERE account_id = $1
    `,
    [id],
  );
  const current = existing.rows[0];
  if (!current) {
    return null;
  }

  const doc = {
    ...current.doc,
    ...stripUndefined(data),
    accountId: current.account_id,
  };
  if (doc.createdAt instanceof Date) {
    doc.createdAt = doc.createdAt.toISOString();
  }
  validateAccountDoc(doc);

  const result = await db.query(
    `
      UPDATE accounts
      SET doc = $2::jsonb
      WHERE account_id = $1
      RETURNING account_id, doc
    `,
    [id, doc],
  );
  return hydrateRow(result.rows[0]);
}

// Delete a accounts by id. Return true if deleted.
export async function deleteAccounts(db, id) {
  const result = await db.query(
    `
      DELETE FROM accounts
      WHERE account_id = $1
    `,
    [id],
  );
  return result.rowCount > 0;
}

