 98	// Update a accounts by id with partial data. Return the updated document.
 99	export async function updateAccounts(db, id, data) {
100	  const existing = await db.query(
101	    `
102	      SELECT account_id, doc
103	      FROM accounts
104	      WHERE account_id = $1
105	    `,
106	    [id],
107	  );
108	  const current = existing.rows[0];
109	  if (!current) {
110	    return null;
111	  }
112	
113	  const doc = {
114	    ...current.doc,
115	    ...stripUndefined(data),
116	    accountId: current.account_id,
117	  };
118	  if (doc.createdAt instanceof Date) {
119	    doc.createdAt = doc.createdAt.toISOString();
120	  }
121	  validateAccountDoc(doc);
122	
123	  const result = await db.query(
124	    `
125	      UPDATE accounts
126	      SET doc = $2::jsonb
127	      WHERE account_id = $1
128	      RETURNING account_id, doc
129	    `,
130	    [id, doc],
131	  );
132	  return hydrateRow(result.rows[0]);
133	}
